
package com.example.taxgap.controller; import com.example.taxgap.domain.dto.report.*; import com.example.taxgap.service.ReportService; import org.springframework.http.ResponseEntity; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/reports") public class ReportController { private final ReportService service; public ReportController(ReportService s){service=s;} @GetMapping("/customers") @PreAuthorize("hasAnyRole('ADMIN','AUDITOR')") public ResponseEntity<List<CustomerTaxSummaryRow>> customers(){ return ResponseEntity.ok(service.customerSummary()); } @GetMapping("/exceptions") @PreAuthorize("hasAnyRole('ADMIN','AUDITOR')") public ResponseEntity<ExceptionSummary> exSummary(){ return ResponseEntity.ok(service.exceptionSummary()); } @GetMapping("/exceptions/per-customer") @PreAuthorize("hasAnyRole('ADMIN','AUDITOR')") public ResponseEntity<List<ExceptionSummary>> exPerCustomer(){ return ResponseEntity.ok(service.exceptionSummaryPerCustomer()); } }
